            return res.json()
        },
        onSuccess: (data: any) => {
            clearDraft()
            const questId = data?.id || editQuestId
            const wasLlmSubmit = scheduleLlm.current
            scheduleLlm.current = false
            if (fundAfterSave.current && questId) {
