}

/* ──────────────────────────────────────────────
   ClawQuest Design Tokens — Base (Terminal Light)
   Theme overrides in styles/themes.css via [data-theme="x"]
   Source of truth: docs/design-system/DESIGN_SYSTEM.md
   ────────────────────────────────────────────── */
:root,
[data-theme="terminal"] {
  /* ── Base surface (body background) ── */
  --bg-base: #fdfdfd;

  /* ── Core Colors (numbered: 1=lightest bg / darkest fg, 4=inverse) ── */
  --bg-1: #ffffff;
  --bg-2: #fafafa;
  --bg-3: #f5f5f5;
  --bg-4: #e5e5e5;
  --fg-1: #171717;
  --fg-2: #404040;
  --fg-3: #737373;
  --fg-4: #d4d4d4;
  --border-1: #f5f5f5;
  --border-2: #e5e5e5;
  --border-3: #d4d4d4;
  --border-4: #a3a3a3;

  /* ── Tailwind color mappings (--color-* consumed by utilities) ── */
  --color-bg-base: var(--bg-base);
  --color-bg-1: var(--bg-1);
  --color-bg-2: var(--bg-2);
  --color-bg-3: var(--bg-3);
  --color-bg-4: var(--bg-4);
  --color-fg-1: var(--fg-1);
  --color-fg-2: var(--fg-2);
  --color-fg-3: var(--fg-3);
  --color-fg-4: var(--fg-4);
  --color-border-1: var(--border-1);
  --color-border-2: var(--border-2);
  --color-border-3: var(--border-3);
  --color-border-4: var(--border-4);

  /* ── Dark surfaces (code blocks, dark cards) ── */
  --surface-dark: #1a1a1a;
  --surface-dark-subtle: #2a2a2a;
  --surface-dark-fg: #ffffff;
  --surface-dark-muted: #999999;

  /* ── Brand / Accent — #FF574B (coral red) ── */
  --accent: #ff574b;
  --accent-hover: #e64a3f;
  --accent-light: #fff0ef;
  --accent-border: #ff574b;
  --accent-fg: #ffffff;

  /* ── Primary (buttons) — brand color ── */
  --primary: #ff574b;
  --primary-hover: #e64a3f;
  --primary-fg: #ffffff;

  /* ── Links ── */
  --link: #ff574b;
  --link-visited: #e64a3f;

  /* ── Semantic ── */
  --success: #16a34a;
  --success-light: #f0fdf4;
  --success-border: #86efac;
  --error: #ff4444;
  --error-light: #fff0f0;
  --error-border: #ff8888;
  --warning: #ffaa00;
  --warning-light: #fff8e6;
  --warning-border: #ffcc66;
  --info: #4488ff;
  --info-light: #e6f0ff;
  --info-border: #88bbff;

  /* ── Actor Colors — monochrome ── */
  --human-fg: #555555;
  --human-bg: #f0f0f0;
  --human-border: #cccccc;
  --agent-fg: #ff574b;
  --agent-bg: #fff0ef;
  --agent-border: #ff574b;
  --skill-fg: #555555;
  --skill-bg: #f0f0f0;
  --skill-border: #cccccc;
  --social-fg: #555555;
  --social-bg: #f0f0f0;

  /* ── Platform Colors ── */
  --stripe-fg: #635bff;
  --stripe-bg: #f3f0ff;
  --telegram: #229ed9;
  --discord: #5865f2;
  --x-twitter: #111111;

  /* ── Tone Colors ── */
  --tone-quest: #ff574b;
  --tone-quest-dark: #e64a3f;
  --tone-quest-bg: #fff0ef;
  --tone-agent: #ff574b;
  --tone-agent-dark: #e64a3f;
  --tone-agent-bg: #fff0ef;

  /* ── Legacy aliases — map to new palette ── */
  --green: #16a34a;
  --green-bg: #f0fdf4;
  --red: #ff4444;
  --red-bg: #fff0f0;
  --yellow: #ffaa00;
  --yellow-bg: #fff8e6;
  --tag-bg: #dcdcdc;
  --tag-fg: #555555;
  --code-bg: #1a1a1a;
  --sidebar-bg: #e8e8e8;

  /* ── Typography — monospace-first ── */
  --font:
    "Geist Mono", ui-monospace, "Cascadia Mono", "Fira Code", "Consolas",
    monospace;
  --font-heading: "D-DIN Exp", "Geist Mono", ui-monospace, monospace;
  --font-mono:
    "Geist Mono", ui-monospace, "Cascadia Mono", "Fira Code", "Consolas",
    monospace;

  --text-2xs: 10px;
  --text-xs: 12px;
  --text-sm: 14px;
  --text-base: 16px;
  --text-md: 16px;
  --text-lg: 18px;
  --text-xl: 20px;
  --text-2xl: 24px;
  --text-3xl: 28px;

  /* ── Spacing (4px grid) ── */
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 12px;
  --space-4: 16px;
  --space-5: 20px;
  --space-6: 24px;
  --space-8: 32px;
  --space-10: 40px;
  --space-12: 48px;
  --space-16: 64px;

  /* ── Border Radius — Terminal: all 0 except pills ── */
  --radius-base: 0px;
  --radius-sm: 0px;
  --radius-md: 0px;
  --radius-lg: 0px;
  --radius-xl: 0px;
  --radius-full: 9999px;
  --radius-button: 0px;

  /* ── Shadows — flat, no decorative shadows ── */
  --shadow-xs: none;
  --shadow-sm: none;
  --shadow-md: 0 1px 3px rgba(0, 0, 0, 0.06);
  --shadow-lg: 0 2px 8px rgba(0, 0, 0, 0.08);
  --shadow-accent: none;

  /* ── Animation ── */
  --duration-fast: 80ms;
  --duration-base: 150ms;
  --duration-slow: 250ms;
  --ease-out: cubic-bezier(0.16, 1, 0.3, 1);
  --ease-in-out: cubic-bezier(0.45, 0, 0.55, 1);
  --transition-fast: var(--duration-fast) var(--ease-out);
  --transition-normal: var(--duration-base) var(--ease-out);

  /* ── Z-Index ── */
  --z-base: 0;
  --z-dropdown: 10;
  --z-sticky: 20;
  --z-overlay: 30;
  --z-modal: 40;
  --z-toast: 50;
}

body {
  font-family: var(--font);
  font-size: var(--text-base);
  line-height: 1.6;
  color: var(--fg-1);
  background: var(--bg-base);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

h1,
h2,
h3,
h4,
h5,
h6 {
  font-family: var(--font-heading);
}

.font-heading {
  font-weight: 600;
}

.text-sm,
.text-base {
  letter-spacing: -0.02em;
}

/* All interactive elements get pointer cursor */
button,
[role="button"],
a,
select,
input[type="checkbox"],
input[type="radio"],
input[type="submit"],
input[type="button"],
label[for],
summary {
  cursor: pointer;
}

/* Global focus ring — disabled for cleaner UI */
:focus-visible {
  outline: none;
}

/* Respect motion preferences */
@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }
}

/* Card hover — shadow + lift */
.hover-shadow {
  @apply transition-all duration-150 ease-out;
}

.hover-shadow:hover {
  @apply -translate-y-0.5;
  box-shadow: var(--shadow-md);
}

/* Skeleton loading placeholder */
.skeleton {
  background: linear-gradient(
    90deg,
    var(--bg-3) 25%,
    var(--border-2) 50%,
    var(--bg-3) 75%
  );
  background-size: 200% 100%;
  animation: skeleton-pulse 1.5s ease-in-out infinite;
  border-radius: var(--radius-sm);
  color: transparent !important;
}

.skeleton * {
  @apply invisible;
}

/* Waitlist mascot card animation (PNG fallback) */
@keyframes float {
  0%,
  100% {
    transform: translateY(0);
  }

  50% {
    transform: translateY(-4px);
  }
}

/* Remove browser default :invalid styling on waitlist inputs */
.waitlist-page input:invalid {
  box-shadow: none;
  outline: none;
}

/* Page transition — opacity-only fade on route change
   No transform — translateY breaks position:fixed/sticky stacking context */
@keyframes page-fade-in {
  from {
    opacity: 0;
  }

  to {
    opacity: 1;
  }
}

.page-fade-in {
  animation: page-fade-in 220ms ease-out both;
}

@keyframes button-pop {
  0% {
    transform: scale(0.95);
  }

  40% {
    transform: scale(1.02);
  }

  to {
    transform: scale(1);
  }
}

.btn-pop:active:not(:disabled) {
  animation: button-pop 0.25s ease-out;
  transform: scale(0.97);
}

@keyframes blink {
  0%,
  100% {
    opacity: 1;
  }

  50% {
    opacity: 0;
  }
}

@keyframes skeleton-pulse {
  0% {
    background-position: 200% 0;
  }

  100% {
    background-position: -200% 0;
  }
}

/* Hide scrollbar for mobile horizontal scroll */
.scrollbar-hide {
  -ms-overflow-style: none;
  /* IE and Edge */
  scrollbar-width: none;
  /* Firefox */
}

.scrollbar-hide::-webkit-scrollbar {
  display: none;
  /* Chrome, Safari, and Opera */
}

/* ═══════════════════════════════════════════
   Animated Banner (.ab-*)
   ═══════════════════════════════════════════ */
/* Illustration container — relative box, flex child, scales with breakpoints */
.ab-illu {
  @apply relative shrink-0 w-[360px] h-[210px] md:w-[380px] md:h-[220px] lg:w-[480px] lg:h-[240px];
}

/* Floating elements: absolute within .ab-illu, sized in % so they scale */
.ab-el {
  @apply absolute;
}

.ab-el:not(.ab-robot) > img {
  @apply w-full block;
}

.ab-cup {
  @apply left-[15%] top-0 w-[14%] z-[5];
}

.ab-robot {
  @apply left-[30%] top-[8%] w-[38%] z-[6];
}

.ab-coin-silver {
  @apply left-[3%] top-[55%] w-[16%] z-[4];
}

.ab-coin-blue {
  @apply right-[3%] top-[3%] w-[15%] z-[4];
}

.ab-pyramid {
  @apply right-[15%] bottom-[15%] w-[5%] z-[5];
}

/* Robot assembly */
.ab-robot-body {
  @apply w-full block relative z-[2];
  filter: drop-shadow(0 4px 16px rgba(243, 74, 66, 0.2));
}

.ab-robot-eyes {
  @apply absolute left-[49%] top-[41%] w-[27%] z-[4] pointer-events-none;
  transition: transform 0.1s ease-out;
}

.ab-robot-arm {
  @apply absolute right-[-28%] top-[18%] w-[48%] z-[1];
  transform-origin: 12% 85%;
  animation: ab-armSway 3.2s ease-in-out infinite;
}

/* Keyframes — entrance */
@keyframes ab-slideDown {
  from {
    opacity: 0;
    transform: translateY(-22px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes ab-slideRight {
  from {
    opacity: 0;
    transform: translateX(22px);
  }

  to {
    opacity: 1;
    transform: translateX(0);
  }
}

@keyframes ab-slideUp {
  from {
    opacity: 0;
    transform: translateY(18px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}

/* Keyframes — gentle float loops */
@keyframes ab-floatB {
  0%,
  100% {
    transform: translateY(0);
  }

  50% {
    transform: translateY(-4%);
  }
}

@keyframes ab-floatCup {
  0%,
  100% {
    transform: translateY(0);
  }

  50% {
    transform: translateY(-5%) rotate(1.5deg);
  }
}

@keyframes ab-coinSilver {
  0%,
  100% {
    transform: translateY(0);
  }

  50% {
    transform: translateY(-5%) rotate(2deg);
  }
}

@keyframes ab-coinBlue {
  0%,
  100% {
    transform: translateY(0);
  }

  50% {
    transform: translateY(-4%) rotate(-1.5deg);
  }
}

@keyframes ab-pyramidWobble {
  0%,
  100% {
    transform: translateY(0) rotate(0deg);
  }

  50% {
    transform: translateY(-6%) rotate(4deg);
  }
}

@keyframes ab-armSway {
  0%,
  100% {
    transform: translate(0, 0) rotate(0deg);
  }

  50% {
    transform: translate(2px, -3px) rotate(1deg);
  }
}

/* Entrance + float assignments */
.ab-cup {
  animation:
    ab-slideDown 0.65s ease-out 0.15s both,
    ab-floatCup 5s ease-in-out 0.8s infinite;
}

.ab-robot {
  animation:
    ab-slideRight 0.75s ease-out 0.25s both,
    ab-floatB 5.5s ease-in-out 1s infinite;
}

.ab-coin-silver {
  animation:
    ab-slideUp 0.65s ease-out 0.35s both,
    ab-coinSilver 6s ease-in-out 1s infinite;
}

.ab-coin-blue {
  animation:
    ab-slideUp 0.65s ease-out 0.45s both,
    ab-coinBlue 6.5s ease-in-out 1.1s infinite;
}

.ab-pyramid {
  animation:
    ab-slideUp 0.6s ease-out 0.5s both,
    ab-pyramidWobble 7s ease-in-out 1.1s infinite;
}

/* UI windows — inline SVG, full height, anchored right behind robot */
.ab-ui-windows {
  @apply absolute right-[-8%] top-0 md:right-0 h-full w-auto block z-2 pointer-events-none;
}

/* Reduce motion */
@media (prefers-reduced-motion: reduce) {
  .ab-el,
  .ab-robot-arm {
    animation: none !important;
  }
}

