@import "tailwindcss";

@plugin 'tailwindcss-animate';

@custom-variant dark (&:is(.dark *));

/* ── D-DIN Exp — heading font ── */
@font-face {
  font-family: "D-DIN Exp";
  src: url("/fonts/D-DINExp.otf") format("opentype");
  font-weight: 400;
  font-style: normal;
  font-display: swap;
}

@font-face {
  font-family: "D-DIN Exp";
  src: url("/fonts/D-DINExp-Bold.otf") format("opentype");
  font-weight: 700;
  font-style: normal;
  font-display: swap;
}

@theme {
  /* ── shadcn aliases → numbered tokens ── */
  --color-background: var(--bg-base);
  --color-foreground: var(--fg-1);

  --color-card: var(--bg-1);
  --color-card-foreground: var(--fg-1);

  --color-popover: var(--bg-1);
  --color-popover-foreground: var(--fg-1);

  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-fg);

  --color-secondary: var(--bg-4);
  --color-secondary-foreground: var(--fg-1);

  --color-muted: var(--bg-4);
  --color-muted-foreground: var(--fg-3);

  --color-destructive: var(--error);
  --color-destructive-foreground: var(--accent-fg);

  --color-input: var(--border-2);
  --color-ring: var(--accent);

  /* ── Base surface (body background) ── */
  --color-bg-base: var(--bg-base);

  /* ── Numbered scale — bg/fg/border ── */
  --color-bg-1: var(--bg-1);
  --color-bg-2: var(--bg-2);
  --color-bg-3: var(--bg-3);
  --color-bg-4: var(--bg-4);

  --color-fg-1: var(--fg-1);
  --color-fg-2: var(--fg-2);
  --color-fg-3: var(--fg-3);
  --color-fg-4: var(--fg-4);

  --color-border-1: var(--border-1);
  --color-border-2: var(--border-2);
  --color-border-3: var(--border-3);
  --color-border-4: var(--border-4);

  /* ── Default border (shadcn) ── */
  --color-border: var(--border-2);

  --color-accent: var(--accent);
  --color-accent-hover: var(--accent-hover);
  --color-accent-light: var(--accent-light);
  --color-border-accent: var(--accent-border);
  --color-accent-foreground: var(--accent-fg);

  --color-success: var(--success);
  --color-success-light: var(--success-light);
  --color-border-success: var(--success-border);

  --color-error: var(--error);
  --color-error-light: var(--error-light);
  --color-border-error: var(--error-border);

  --color-warning: var(--warning);
  --color-warning-light: var(--warning-light);
  --color-border-warning: var(--warning-border);

  --color-info: var(--info);
  --color-info-light: var(--info-light);
  --color-border-info: var(--info-border);

  --color-human: var(--human-fg);
  --color-human-bg: var(--human-bg);
  --color-human-border: var(--human-border);

  --color-agent: var(--agent-fg);
  --color-agent-bg: var(--agent-bg);
  --color-agent-border: var(--agent-border);

  --color-skill: var(--skill-fg);
  --color-skill-bg: var(--skill-bg);
  --color-skill-border: var(--skill-border);

  --color-link: var(--link);

  --color-surface-dark: var(--surface-dark);
  --color-surface-dark-subtle: var(--surface-dark-subtle);
  --color-surface-dark-fg: var(--surface-dark-fg);
  --color-surface-dark-muted: var(--surface-dark-muted);

  --font-sans: var(--font);
  --font-heading: "D-DIN Exp", "Geist Mono", ui-monospace, monospace;
  --font-mono: var(--font-mono);

  --text-2xs: 10px;
  --text-xs: var(--text-xs);
  --text-sm: var(--text-sm);
  --text-base: var(--text-base);
  --text-md: var(--text-md);
  --text-lg: var(--text-lg);
