  --accent: #ff574b;
  --accent-hover: #e64a3f;
  --accent-light: #fff0ef;
  --accent-border: #ff574b;
  --accent-fg: #ffffff;

  /* ── Primary (buttons) — brand color ── */
  --primary: #ff574b;
  --primary-hover: #e64a3f;
  --primary-fg: #ffffff;

  /* ── Links ── */
